### 4. **Using DiagnosticTag (Unnecessary and Deprecated)**

**Location**: `/workspace/repo/extensions/typescript-language-features/src/typeScriptServiceClientHost.ts`

```typescript
private tsDiagnosticToVsDiagnostic(diagnostic: Proto.Diagnostic, source: string): vscode.Diagnostic {
    const converted = new vscode.Diagnostic(range, text, this.getDiagnosticSeverity(diagnostic));
    converted.source = diagnostic.source || source;

    // Create tags array
    const tags: vscode.DiagnosticTag[] = [];

    // Mark as unnecessary (unused code, etc.)
    if (diagnostic.reportsUnnecessary) {
        tags.push(vscode.DiagnosticTag.Unnecessary);
    }

    // Mark as deprecated
    if (diagnostic.reportsDeprecated) {
        tags.push(vscode.DiagnosticTag.Deprecated);
    }

    converted.tags = tags.length ? tags : undefined;
    return converted;
}
```

