### 5. **Using DiagnosticRelatedInformation**

**Location**: `/workspace/repo/extensions/typescript-language-features/src/typeScriptServiceClientHost.ts`

```typescript
private tsDiagnosticToVsDiagnostic(diagnostic: Proto.Diagnostic, source: string): vscode.Diagnostic {
    const converted = new vscode.Diagnostic(range, text, this.getDiagnosticSeverity(diagnostic));

    const relatedInformation = diagnostic.relatedInformation;
    if (relatedInformation) {
        converted.relatedInformation = coalesce(relatedInformation.map((info: any) => {
            const span = info.span;
            if (!span) {
                return undefined;
            }
            return new vscode.DiagnosticRelatedInformation(
                typeConverters.Location.fromTextSpan(this.client.toResource(span.file), span), 
                info.message
            );
        }));
    }

    return converted;
}
```

